{
  "name": "LuminaLib - Smart E-Library",
  "description": "A feature-rich E-Library MVP with AI-powered book summaries, intelligent search, and a full administrative dashboard.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
