import React, { useState, useEffect } from 'react';
import { libraryService } from '../services/libraryService';
import { geminiService } from '../services/geminiService';
import { Book } from '../types';
import { CATEGORIES } from '../constants';

const Admin: React.FC = () => {
  const [books, setBooks] = useState<Book[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingId, setEditingId] = useState<number | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  // Form State
  const [formData, setFormData] = useState({
    title: '',
    author: '',
    description: '',
    categories: [] as string[],
    publishedYear: 2024,
    coverImageUrl: ''
  });

  useEffect(() => {
    refreshBooks();
  }, []);

  const refreshBooks = () => {
    setBooks(libraryService.getAllBooks());
  };

  const openAddModal = () => {
    setEditingId(null);
    setFormData({
      title: '',
      author: '',
      description: '',
      categories: [],
      publishedYear: 2024,
      coverImageUrl: ''
    });
    setIsModalOpen(true);
  };

  const openEditModal = (book: Book) => {
    setEditingId(book.id);
    setFormData({
      title: book.title,
      author: book.author,
      description: book.description,
      categories: book.categories,
      publishedYear: book.publishedYear || 2024,
      coverImageUrl: book.coverImageUrl || ''
    });
    setIsModalOpen(true);
  };

  const handleDelete = (id: number) => {
    if (confirm('Are you sure you want to delete this book?')) {
      libraryService.deleteBook(id);
      refreshBooks();
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingId) {
      libraryService.updateBook(editingId, formData);
    } else {
      libraryService.addBook(formData);
    }
    setIsModalOpen(false);
    refreshBooks();
  };

  const toggleCategory = (cat: string) => {
    setFormData(prev => ({
      ...prev,
      categories: prev.categories.includes(cat)
        ? prev.categories.filter(c => c !== cat)
        : [...prev.categories, cat]
    }));
  };

  const handleAiAutoFill = async () => {
    if (!formData.title || !formData.author) {
      alert('Please enter Title and Author first for AI to generate info.');
      return;
    }
    setIsLoading(true);
    try {
      const result = await geminiService.generateBookDescription(formData.title, formData.author);
      setFormData(prev => ({
        ...prev,
        description: result.description,
        categories: result.categories,
        publishedYear: result.year
      }));
    } catch (error) {
      alert('AI Auto-fill failed. Please try manual entry.');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="space-y-10 animate-fadeIn">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6">
        <div>
          <h1 className="text-4xl font-extrabold text-slate-900 tracking-tight">Library Manager</h1>
          <p className="text-slate-500 mt-2">Add, update, or remove titles from your collection.</p>
        </div>
        <button 
          onClick={openAddModal}
          className="flex items-center space-x-2 px-6 py-3 bg-blue-600 text-white font-bold rounded-2xl shadow-lg hover:bg-blue-500 transition-all transform active:scale-95"
        >
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
          </svg>
          <span>Add New Book</span>
        </button>
      </div>

      {/* Book Table */}
      <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-xl overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50 border-b border-slate-100">
                <th className="px-6 py-5 text-sm font-bold text-slate-400 uppercase tracking-widest">Book</th>
                <th className="px-6 py-5 text-sm font-bold text-slate-400 uppercase tracking-widest hidden md:table-cell">Categories</th>
                <th className="px-6 py-5 text-sm font-bold text-slate-400 uppercase tracking-widest hidden sm:table-cell">Published</th>
                <th className="px-6 py-5 text-sm font-bold text-slate-400 uppercase tracking-widest text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {books.map(book => (
                <tr key={book.id} className="hover:bg-slate-50 transition-colors group">
                  <td className="px-6 py-5">
                    <div className="flex items-center space-x-4">
                      <div className="w-12 h-16 rounded-lg overflow-hidden bg-slate-100 flex-shrink-0">
                         <img src={book.coverImageUrl || `https://picsum.photos/seed/${book.id}/400/600`} alt="" className="w-full h-full object-cover" />
                      </div>
                      <div>
                        <p className="font-bold text-slate-900 group-hover:text-blue-600 transition-colors">{book.title}</p>
                        <p className="text-sm text-slate-500">{book.author}</p>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-5 hidden md:table-cell">
                    <div className="flex flex-wrap gap-1">
                      {book.categories.slice(0, 2).map(cat => (
                        <span key={cat} className="px-2 py-1 bg-blue-50 text-blue-600 text-[10px] font-bold uppercase rounded border border-blue-100">{cat}</span>
                      ))}
                    </div>
                  </td>
                  <td className="px-6 py-5 hidden sm:table-cell text-slate-500">
                    {book.publishedYear}
                  </td>
                  <td className="px-6 py-5 text-right space-x-2">
                    <button 
                      onClick={() => openEditModal(book)}
                      className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-xl transition-all"
                    >
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
                      </svg>
                    </button>
                    <button 
                      onClick={() => handleDelete(book.id)}
                      className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all"
                    >
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                      </svg>
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setIsModalOpen(false)}></div>
          <div className="relative w-full max-w-2xl bg-white rounded-[2.5rem] shadow-2xl p-8 max-h-[90vh] overflow-y-auto border border-slate-100">
            <h2 className="text-3xl font-bold text-slate-900 mb-8">{editingId ? 'Edit Book' : 'Add New Book'}</h2>

            <form onSubmit={handleSubmit} className="space-y-6">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-sm font-bold text-slate-700 uppercase tracking-widest">Title *</label>
                  <input 
                    required
                    type="text" 
                    value={formData.title}
                    onChange={(e) => setFormData(p => ({...p, title: e.target.value}))}
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-bold text-slate-700 uppercase tracking-widest">Author *</label>
                  <input 
                    required
                    type="text" 
                    value={formData.author}
                    onChange={(e) => setFormData(p => ({...p, author: e.target.value}))}
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                  />
                </div>
              </div>

              {/* AI Trigger */}
              <div className="bg-blue-50 p-4 rounded-2xl flex items-center justify-between border border-blue-100">
                 <div className="flex items-center space-x-3">
                   <div className="w-10 h-10 bg-blue-600 rounded-lg flex items-center justify-center text-white">
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
                      </svg>
                   </div>
                   <div>
                     <p className="font-bold text-blue-900 text-sm">Smart Fill</p>
                     <p className="text-xs text-blue-700">Let AI generate the description & details.</p>
                   </div>
                 </div>
                 <button 
                  type="button"
                  disabled={isLoading}
                  onClick={handleAiAutoFill}
                  className="px-4 py-2 bg-white text-blue-600 border border-blue-200 font-bold text-sm rounded-xl shadow-sm hover:shadow-md transition-all flex items-center space-x-2"
                 >
                   {isLoading ? <div className="w-4 h-4 border-2 border-blue-600 border-t-transparent rounded-full animate-spin"></div> : 'Auto-fill'}
                 </button>
              </div>

              <div className="space-y-2">
                <label className="text-sm font-bold text-slate-700 uppercase tracking-widest">Description *</label>
                <textarea 
                  required
                  rows={4}
                  value={formData.description}
                  onChange={(e) => setFormData(p => ({...p, description: e.target.value}))}
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all resize-none"
                />
              </div>

              <div className="space-y-4">
                <label className="text-sm font-bold text-slate-700 uppercase tracking-widest">Categories</label>
                <div className="flex flex-wrap gap-2">
                  {CATEGORIES.map(cat => (
                    <button 
                      key={cat}
                      type="button"
                      onClick={() => toggleCategory(cat)}
                      className={`px-3 py-1.5 rounded-lg text-xs font-bold uppercase transition-all ${
                        formData.categories.includes(cat)
                          ? 'bg-blue-600 text-white shadow-md'
                          : 'bg-slate-100 text-slate-500 hover:bg-slate-200'
                      }`}
                    >
                      {cat}
                    </button>
                  ))}
                </div>
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-sm font-bold text-slate-700 uppercase tracking-widest">Published Year</label>
                  <input 
                    type="number" 
                    value={formData.publishedYear}
                    onChange={(e) => setFormData(p => ({...p, publishedYear: parseInt(e.target.value)}))}
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-bold text-slate-700 uppercase tracking-widest">Cover Image URL</label>
                  <input 
                    type="url" 
                    value={formData.coverImageUrl}
                    onChange={(e) => setFormData(p => ({...p, coverImageUrl: e.target.value}))}
                    placeholder="https://example.com/cover.jpg"
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                  />
                </div>
              </div>

              <div className="flex justify-end space-x-4 pt-6">
                <button 
                  type="button"
                  onClick={() => setIsModalOpen(false)}
                  className="px-6 py-3 font-bold text-slate-400 hover:text-slate-600 transition-colors"
                >
                  Cancel
                </button>
                <button 
                  type="submit"
                  className="px-8 py-3 bg-blue-600 text-white font-bold rounded-2xl shadow-lg hover:bg-blue-500 transition-all transform active:scale-95"
                >
                  {editingId ? 'Save Changes' : 'Create Book'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Admin;

