import { Book, SortOption } from '../types.ts';
import { INITIAL_BOOKS } from '../constants.tsx';

const STORAGE_KEY = 'openshelf_data';

export const libraryService = {
  getStore: () => {
    const data = localStorage.getItem(STORAGE_KEY);
    if (!data) {
      const initial = { books: INITIAL_BOOKS, nextId: INITIAL_BOOKS.length + 1 };
      localStorage.setItem(STORAGE_KEY, JSON.stringify(initial));
      return initial;
    }
    return JSON.parse(data);
  },

  saveStore: (books: Book[], nextId: number) => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify({ books, nextId }));
  },

  getAllBooks: (): Book[] => {
    return libraryService.getStore().books;
  },

  getBook: (id: number): Book | undefined => {
    return libraryService.getStore().books.find((b: Book) => b.id === id);
  },

  addBook: (book: Omit<Book, 'id' | 'createdAt'>): Book => {
    const { books, nextId } = libraryService.getStore();
    const newBook: Book = {
      ...book,
      id: nextId,
      createdAt: Date.now()
    };
    libraryService.saveStore([...books, newBook], nextId + 1);
    return newBook;
  },

  updateBook: (id: number, updated: Partial<Book>): boolean => {
    const { books, nextId } = libraryService.getStore();
    const index = books.findIndex((b: Book) => b.id === id);
    if (index === -1) return false;

    books[index] = { ...books[index], ...updated };
    libraryService.saveStore(books, nextId);
    return true;
  },

  deleteBook: (id: number): boolean => {
    const { books, nextId } = libraryService.getStore();
    const filtered = books.filter((b: Book) => b.id !== id);
    if (filtered.length === books.length) return false;
    libraryService.saveStore(filtered, nextId);
    return true;
  },

  searchAndFilter: (keyword: string, category: string, sort: SortOption): Book[] => {
    let books = libraryService.getAllBooks();

    if (keyword) {
      const lower = keyword.toLowerCase();
      books = books.filter(b => 
        b.title.toLowerCase().includes(lower) || 
        b.author.toLowerCase().includes(lower) ||
        b.description.toLowerCase().includes(lower)
      );
    }

    if (category && category !== 'All') {
      books = books.filter(b => b.categories.includes(category));
    }

    switch (sort) {
      case SortOption.NEWEST:
        books.sort((a, b) => b.createdAt - a.createdAt);
        break;
      case SortOption.OLDEST:
        books.sort((a, b) => a.createdAt - b.createdAt);
        break;
      case SortOption.TITLE_ASC:
        books.sort((a, b) => a.title.localeCompare(b.title));
        break;
      case SortOption.TITLE_DESC:
        books.sort((a, b) => b.title.localeCompare(a.title));
        break;
    }

    return books;
  }
};

import { GoogleGenAI, Type } from "@google/genai";
import { Book } from "../types.ts";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const geminiService = {
  async getBookSummary(book: Book): Promise<string> {
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Provide an insightful, engaging 3-sentence summary of the book "${book.title}" by ${book.author}. Focus on the main themes and why it's worth reading.`,
        config: {
          thinkingConfig: { thinkingBudget: 0 }
        }
      });
      return response.text || "No summary available.";
    } catch (error) {
      console.error("Gemini Summary Error:", error);
      return "Could not generate AI summary at this time.";
    }
  },

  async askLibrarian(question: string, books: Book[]): Promise<string> {
    try {
      const catalog = books.map(b => `${b.title} by ${b.author} (${b.categories.join(', ')})`).join('\n');
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `You are a helpful and knowledgeable digital librarian for 'Open Shelf Library'. 
        The current book catalog is:
        ${catalog}

        User's question: ${question}

        Provide a friendly, concise answer. If they ask for recommendations, suggest books from the catalog that match their interest.`,
      });
      return response.text || "I'm not sure how to answer that. Try asking about our books!";
    } catch (error) {
      console.error("Gemini Chat Error:", error);
      return "I'm having trouble connecting to my brain right now. Please try again later!";
    }
  },

  async generateBookDescription(title: string, author: string): Promise<{ description: string; categories: string[]; year: number }> {
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Generate a book record for "${title}" by ${author}. 
        Return a JSON object with: 
        - description: A professional book blurb.
        - categories: Array of 2-3 matching literary categories.
        - year: The original publication year as a number.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              description: { type: Type.STRING },
              categories: { type: Type.ARRAY, items: { type: Type.STRING } },
              year: { type: Type.NUMBER }
            },
            required: ["description", "categories", "year"]
          }
        }
      });
      return JSON.parse(response.text);
    } catch (error) {
      console.error("Gemini Auto-fill Error:", error);
      throw error;
    }
  }
};

