          </div>
          <h2 className="text-4xl font-extrabold text-[#F5EFEA] tracking-tight">Welcome Back</h2>
          <p className="mt-3 text-[#CBB8A9]">Enter your credentials to access your library</p>
        </div>

        <form className="mt-8 space-y-6" onSubmit={handleLogin}>
          <div className="space-y-4">
            <div className="space-y-2">
              <label className="text-xs font-bold text-[#8C7A6B] uppercase tracking-widest ml-1">Username or Email</label>
              <input
                required
                type="text"
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                placeholder="librarian@openshelf.com"
                className="w-full px-5 py-4 bg-[#1F1511] border border-[#3A2A23] text-[#F5EFEA] rounded-2xl focus:ring-2 focus:ring-[#E6B18A] outline-none transition-all placeholder:text-[#8C7A6B]"
              />
            </div>
            <div className="space-y-2">
              <label className="text-xs font-bold text-[#8C7A6B] uppercase tracking-widest ml-1">Password</label>
              <input
                required
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="••••••••"
                className="w-full px-5 py-4 bg-[#1F1511] border border-[#3A2A23] text-[#F5EFEA] rounded-2xl focus:ring-2 focus:ring-[#E6B18A] outline-none transition-all placeholder:text-[#8C7A6B]"
              />
            </div>
          </div>

          <div className="flex items-center justify-between px-1">
            <div className="flex items-center">
              <input
                id="remember-me"
                name="remember-me"
                type="checkbox"
                className="h-4 w-4 text-[#E6B18A] focus:ring-[#E6B18A] border-[#3A2A23] bg-[#1F1511] rounded"
              />
              <label htmlFor="remember-me" className="ml-2 block text-sm text-[#CBB8A9]">
                Remember me
              </label>
            </div>
            <div className="text-sm">
              <a href="#" className="font-bold text-[#E6B18A] hover:text-[#D39A70]">
                Forgot password?
              </a>
            </div>
          </div>

          <div>
            <button
              type="submit"
              className="group relative w-full flex justify-center py-4 px-4 bg-[#E6B18A] text-[#1A120E] font-bold rounded-2xl shadow-xl hover:bg-[#D39A70] transition-all transform active:scale-95"
            >
              Sign In
            </button>
          </div>
        </form>

        <p className="text-center text-sm text-[#8C7A6B]">
          Don't have an account?{' '}
          <a href="#" className="font-bold text-[#E6B18A] hover:text-[#D39A70]">
            Request access
          </a>
        </p>
      </div>
    </div>
  );
};

export default Login;

import React from 'react';
import { HashRouter as Router, Routes, Route } from 'react-router-dom';
import Layout from './components/Layout.tsx';
import Home from './pages/Home.tsx';
import Browse from './pages/Browse.tsx';
import BookDetails from './pages/BookDetails.tsx';
import Admin from './pages/Admin.tsx';
import Login from './pages/Login.tsx';
import Privacy from './pages/Privacy.tsx';
import Terms from './pages/Terms.tsx';
import LibrarianChat from './components/LibrarianChat.tsx';

const App: React.FC = () => {
  return (
    <Router>
      <Layout>
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/browse" element={<Browse />} />
          <Route path="/book/:id" element={<BookDetails />} />
          <Route path="/admin" element={<Admin />} />
          <Route path="/login" element={<Login />} />
          <Route path="/privacy" element={<Privacy />} />
          <Route path="/terms" element={<Terms />} />
        </Routes>
      </Layout>
      <LibrarianChat />
    </Router>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { authService } from '../services/authService.ts';

const NavLink: React.FC<{ to: string; children: React.ReactNode }> = ({ to, children }) => {
  const location = useLocation();
  const isActive = location.pathname === to || (to !== '/' && location.pathname.startsWith(to));

  return (
    <Link 
      to={to} 
      className={`px-4 py-2 rounded-full transition-all duration-300 font-medium ${
        isActive 
          ? 'bg-[#E6B18A] text-[#1A120E] shadow-lg shadow-[#E6B18A]/20' 
          : 'text-[#CBB8A9] hover:text-[#F5EFEA] hover:bg-[#241814]'
      }`}
    >
      {children}
    </Link>
  );
};

const Layout: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [isAuthenticated, setIsAuthenticated] = useState(authService.isAuthenticated());
  const navigate = useNavigate();
  const location = useLocation();

  useEffect(() => {
    const handleAuth = () => setIsAuthenticated(authService.isAuthenticated());
    window.addEventListener('authChange', handleAuth);
    const interval = setInterval(handleAuth, 1000);
    return () => {
      window.removeEventListener('authChange', handleAuth);
      clearInterval(interval);
    };
  }, []);

  const handleLogout = () => {
    authService.logout();
    setIsAuthenticated(false);
    window.dispatchEvent(new Event('authChange'));
    navigate('/login');
  };

  return (
    <div className="min-h-screen flex flex-col bg-[#1A120E]">
      <header className="sticky top-0 z-50 glass-effect">
        <nav className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-4">
            {isAuthenticated && (
              <button 
                onClick={handleLogout}
                className="p-2 text-[#8C7A6B] hover:text-red-400 hover:bg-red-400/5 rounded-xl transition-all flex items-center group"
                title="Logout"
              >
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" />
                </svg>
                <span className="ml-2 hidden lg:inline font-bold text-xs uppercase tracking-widest">Logout</span>
              </button>
            )}

            <Link to="/" className="flex items-center space-x-2">
              <div className="w-10 h-10 bg-[#E6B18A] rounded-xl flex items-center justify-center shadow-lg transform rotate-3 hover:rotate-0 transition-transform">
                <span className="text-[#1A120E] font-bold text-xl">O</span>
              </div>
              <span className="text-xl font-bold text-[#F5EFEA] tracking-tight">
                Open Shelf
              </span>
            </Link>
          </div>

          <div className="hidden md:flex items-center space-x-2">
            <NavLink to="/">Home</NavLink>
            <NavLink to="/browse">Browse</NavLink>
            <NavLink to="/admin">Manage</NavLink>
            {!isAuthenticated && location.pathname !== '/login' && (
              <NavLink to="/login">Login</NavLink>
            )}
          </div>

          <button className="md:hidden p-2 text-[#CBB8A9]">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16m-7 6h7" />
            </svg>
          </button>
        </nav>
      </header>

      <main className="flex-grow max-w-7xl mx-auto w-full px-4 py-8">
        {children}
      </main>

      <footer className="bg-[#241814] text-[#CBB8A9] py-12 border-t border-[#3A2A23]">
        <div className="max-w-7xl mx-auto px-4 text-center">
          <div className="flex justify-center items-center space-x-2 mb-6">
             <div className="w-8 h-8 bg-[#E6B18A] rounded flex items-center justify-center text-[#1A120E] font-bold">O</div>
             <span className="text-[#F5EFEA] font-bold text-lg">Open Shelf Library</span>
          </div>
          <p className="max-w-md mx-auto mb-8 text-[#8C7A6B]">
            Elevating your reading experience with intelligent cataloging and AI-driven insights. Built for the modern bibliophile.
          </p>
          <div className="flex justify-center space-x-6 mb-8">
            <Link to="/privacy" className="hover:text-[#F5EFEA] transition-colors">Privacy</Link>
            <Link to="/terms" className="hover:text-[#F5EFEA] transition-colors">Terms</Link>
            <a href="#" className="hover:text-[#F5EFEA] transition-colors">API</a>
          </div>
          <p className="text-sm text-[#8C7A6B]">
            &copy; {new Date().getFullYear()} Open Shelf Library MVP. Powered by Google Gemini.
          </p>
        </div>
      </footer>
    </div>
  );
};

export default Layout;
